def deduplicate(data):
    result = []
    for item in data:
        if item not in result:
            result.append(item)
    return result
def main():
    data = [1, 2, 2, 3, 4, 4, 5]
    unique = deduplicate(data)
    print("Unique values:", unique)
main()

