def withdraw(balance, amount):
    if amount <= balance:
        balance -= amount
    else:
        print("Insufficient funds")
    return balance
def main():
    balance = 1000
    amount = 200
    balance = withdraw(balance, amount)
    print("Remaining balance:", balance)
main()

