def calculate_cart_total(cart_items):
    total = 0
    for item in cart_items:
        price = item["price"]
        quantity = item["quantity"]
        total = total + price * quantity
    return total
def apply_tax(total, tax_rate):
    return total + total * tax_rate
def main():
    cart = [
        {"name": "Book", "price": 12.5, "quantity": 2},
        {"name": "Pen", "price": 1.5, "quantity": 5}
    ]
    subtotal = calculate_cart_total(cart)
    final_total = apply_tax(subtotal, 0.1)
    print("Final cart total:", final_total)
main()

