def find_user(users, target_id):
    for i in range(len(users)):
        if users[i]["id"] == target_id:
            return users[i]
    return None
def main():
    users = [
        {"id": 1, "name": "Alice"},
        {"id": 2, "name": "Bob"}
    ]
    user = find_user(users, 3)
    print("User found:", user["name"])
main()

